import torch, torch.nn.functional as F
class CRM(torch.nn.Module):
    def __init__(self, phi): super().__init__(); self.phi = phi
    def forward(self, h):
        cs = F.cosine_similarity(h, self.phi, dim=-1)
        return { 'cosine': cs.mean().item(), 'delta': 1 - cs.mean().item() }

